import{_ as e,o as i,c as s,a2 as l}from"./chunks/framework.tNPPebLH.js";const k=JSON.parse('{"title":"常见问题与排错","description":"","frontmatter":{},"headers":[],"relativePath":"troubleshooting.md","filePath":"troubleshooting.md","lastUpdated":1783841449000}'),t={name:"troubleshooting.md"};function n(r,a,p,o,h,d){return i(),s("div",null,[...a[0]||(a[0]=[l(`<h1 id="常见问题与排错" tabindex="-1">常见问题与排错 <a class="header-anchor" href="#常见问题与排错" aria-label="Permalink to &quot;常见问题与排错&quot;">​</a></h1><h2 id="windows-安装器被-smartscreen-拦截" tabindex="-1">Windows 安装器被 SmartScreen 拦截 <a class="header-anchor" href="#windows-安装器被-smartscreen-拦截" aria-label="Permalink to &quot;Windows 安装器被 SmartScreen 拦截&quot;">​</a></h2><p>社区构建暂未配置商业代码签名。确认文件来自本仓库 Release，并核对 <code>SHA256SUMS.txt</code> 后，可以在 SmartScreen 中选择“更多信息”再决定是否运行。</p><p>不要从第三方网盘运行文件名相同但哈希不同的安装包。</p><h2 id="macos-提示应用已损坏或无法验证开发者" tabindex="-1">macOS 提示应用已损坏或无法验证开发者 <a class="header-anchor" href="#macos-提示应用已损坏或无法验证开发者" aria-label="Permalink to &quot;macOS 提示应用已损坏或无法验证开发者&quot;">​</a></h2><p>先确认下载的架构正确：</p><ul><li>Apple Silicon 使用 <code>aarch64</code> DMG；</li><li>Intel Mac 使用 <code>x64</code> / <code>x86_64</code> DMG。</li></ul><p>社区构建使用 ad-hoc 签名，不等同于 Apple Developer ID 公证。优先在 Finder 中按住 Control 点击应用并选择“打开”。如果系统仍然阻止，确认来源和 SHA-256 后再清除下载隔离属性：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">xattr</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -cr</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;/Applications/PetPack Studio.app&quot;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>公开分发者应配置正式签名和公证，而不是要求普通用户长期绕过 Gatekeeper。</p><h2 id="appimage-双击没有反应" tabindex="-1">AppImage 双击没有反应 <a class="header-anchor" href="#appimage-双击没有反应" aria-label="Permalink to &quot;AppImage 双击没有反应&quot;">​</a></h2><p>赋予执行权限：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">chmod</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> +x</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;PetPack Studio_0.3.1_amd64.AppImage&quot;</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">./</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">&quot;PetPack Studio_0.3.1_amd64.AppImage&quot;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>部分发行版还需要 FUSE 2。也可以改用 DEB 包。</p><h2 id="桌宠只显示一部分" tabindex="-1">桌宠只显示一部分 <a class="header-anchor" href="#桌宠只显示一部分" aria-label="Permalink to &quot;桌宠只显示一部分&quot;">​</a></h2><p>0.3.1 已修复 Studio 全局最小尺寸影响桌宠运行时的问题。请确认：</p><ol><li>桌宠 EXE/App 与 <code>petpack.bundle</code> 来自同一次导出；</li><li>没有只复制旧版运行程序；</li><li>使用 0.3.1 或更高版本重新打包；</li><li>删除旧 ZIP 后再分发新 ZIP。</li></ol><h2 id="桌宠不能拖动" tabindex="-1">桌宠不能拖动 <a class="header-anchor" href="#桌宠不能拖动" aria-label="Permalink to &quot;桌宠不能拖动&quot;">​</a></h2><p>拖动区域是角色底部的三点把手，不是整个透明窗口。按住把手再移动。如果工具栏覆盖把手，先把光标移开再重新进入。</p><h2 id="桌宠不在任务栏" tabindex="-1">桌宠不在任务栏 <a class="header-anchor" href="#桌宠不在任务栏" aria-label="Permalink to &quot;桌宠不在任务栏&quot;">​</a></h2><p>这是预期行为。独立桌宠只在系统托盘显示入口。使用悬停工具栏或托盘菜单退出。</p><p>Studio 本身应该显示在任务栏：最小化后仍可恢复，点击关闭按钮会结束进程。</p><h2 id="调整大小后宠物跑出屏幕" tabindex="-1">调整大小后宠物跑出屏幕 <a class="header-anchor" href="#调整大小后宠物跑出屏幕" aria-label="Permalink to &quot;调整大小后宠物跑出屏幕&quot;">​</a></h2><p>0.3.1 会在缩放后重新检查当前显示器边界。旧版本可能混用物理像素和逻辑坐标，请使用新版本重新导出桌宠。</p><h2 id="导入按钮一直禁用发布" tabindex="-1">导入按钮一直禁用发布 <a class="header-anchor" href="#导入按钮一直禁用发布" aria-label="Permalink to &quot;导入按钮一直禁用发布&quot;">​</a></h2><p>查看“检查与预览”下方错误信息。常见原因：</p><ul><li>图集尺寸不是支持的 8×9 或 8×11 网格；</li><li><code>spritesheetPath</code> 指向包外文件；</li><li>必需使用帧为空；</li><li>未使用单元格含有残留像素；</li><li>ZIP 中包含多个 <code>pet.json</code>；</li><li>清单或图集超过大小限制。</li></ul><h2 id="跨平台构建包缺少目标-builder" tabindex="-1">跨平台构建包缺少目标 builder <a class="header-anchor" href="#跨平台构建包缺少目标-builder" aria-label="Permalink to &quot;跨平台构建包缺少目标 builder&quot;">​</a></h2><p>构建包会优先使用随包携带的当前平台 builder；若缺少，系统入口会在首次运行从 <code>builder-v0.3.1</code> Release 自动下载。自动下载失败时，可从该 Release 手动取得对应架构压缩包并解压到 <code>builders/</code>，或使用 <code>build-pet.yml</code> 在目标平台 runner 上构建。</p><h2 id="docker-无法拉取基础镜像" tabindex="-1">Docker 无法拉取基础镜像 <a class="header-anchor" href="#docker-无法拉取基础镜像" aria-label="Permalink to &quot;Docker 无法拉取基础镜像&quot;">​</a></h2><p>先检查 Docker Desktop 或 Docker daemon 的代理配置。若日志仍指向已停用的 <code>127.0.0.1</code> 代理，需要在 Docker 设置中改为有效代理或系统代理。修改全局代理前应确认不会影响其他容器。</p><p>应用级检查：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">docker</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> compose</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> config</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">docker</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> compose</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> build</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">docker</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> compose</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> up</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -d</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> http://localhost:8080/healthz</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><h2 id="如何提交问题" tabindex="-1">如何提交问题 <a class="header-anchor" href="#如何提交问题" aria-label="Permalink to &quot;如何提交问题&quot;">​</a></h2><p>在 <a href="https://github.com/MingfengHong/petpack/issues" target="_blank" rel="noreferrer">GitHub Issues</a> 提供：</p><ul><li>Studio 版本；</li><li>操作系统、CPU 架构和显示缩放比例；</li><li>导入来源类型；</li><li>错误信息或截图；</li><li>是否能用示例宠物复现；</li><li>产物 SHA-256（不要上传无授权宠物素材）。</li></ul>`,36)])])}const u=e(t,[["render",n]]);export{k as __pageData,u as default};
